onClick:
{{
  (async () => {
    try {
      // 1. Chạy lệnh UPDATE
      const resUpdate = await Action_Update_Kho_V2.run();

      // --- SỬA CHỖ NÀY ---
      // Vì Database trả về mảng [ {affectedRows: 0} ], 
      // nên ta phải lấy phần tử đầu tiên resUpdate[0]
      const rowsAffected = resUpdate[0].affectedRows;

      console.log("Số dòng thực tế:", rowsAffected);

      // 2. Chặn xuất kho nếu rowsAffected == 0
      if (rowsAffected === 0) {
        return showAlert("⚠️ CHẶN XUẤT: Không đủ tồn kho hoặc mã sai!", "error");
      }

      // 3. Chỉ chạy INSERT nếu rowsAffected > 0
      await Action_Insert_Log_V2.run();

      showAlert("✅ Xuất kho thành công!", "success");

      // Làm mới
      await Get_LichSu_Xuat_V2.run();
      await Get_Tong_Kho_Phu_Tung.run();
      resetWidget("Form_Xuat_Nhap", true);

    } catch (err) {
      console.error("Lỗi:", err);
      showAlert("❌ Lỗi: " + err.message, "error");
    }
  })()
}}
